mapper.select:
SELECT * FROM SCM_RJ_SIMP.ALERT_RESULT
WHERE 1 = 1

    AND ALERT_RULE_ID IN (SELECT ID FROM SCM_RJ_SIMP.ALERT_RULE WHERE NAME LIKE CONCAT('%', #{keyword}, '%'))


    AND ALERT_LEVEL = #{alertLevel}


    AND RULE_TYPE = #{ruleType}

ORDER BY CREATE_TIME DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM SCM_RJ_SIMP.ALERT_RESULT
WHERE 1 = 1

    AND ALERT_RULE_ID IN (SELECT ID FROM SCM_RJ_SIMP.ALERT_RULE WHERE NAME LIKE CONCAT('%', #{keyword}, '%'))


    AND ALERT_LEVEL = #{alertLevel}


    AND RULE_TYPE = #{ruleType}

SELECT COUNT(*) FROM SCM_RJ_SIMP.ALERT_RESULT
WHERE NORMAL_RULE_ID = #{normalRuleId}
  AND CREATE_TIME >= #{startTime}
